import React, { useRef, useState, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera } from '@react-three/drei';
import { useLocation, useNavigate } from 'react-router-dom';
import * as THREE from 'three';

// Single small cube (one of 27)
const SmallCube = ({ position, colors }) => {
  // colors = { right, left, up, down, front, back } or null for no color
  const createMaterial = (color, isVisible) => {
    if (!isVisible || !color) return null;
    return new THREE.MeshStandardMaterial({ color: color, roughness: 0.3, metalness: 0.05 });
  };

  const materials = [
    createMaterial(colors.right, true),   // right
    createMaterial(colors.left, true),    // left
    createMaterial(colors.up, true),      // up
    createMaterial(colors.down, true),    // down
    createMaterial(colors.front, true),   // front
    createMaterial(colors.back, true),    // back
  ];

  return (
    <mesh position={position}>
      <boxGeometry args={[0.96, 0.96, 0.96]} />
      {materials.map((mat, i) => mat && <meshStandardMaterial key={i} attach={`material-${i}`} {...mat} />)}
    </mesh>
  );
};

// Full Rubik's Cube (27 small cubes)
const RubiksCube = () => {
  const colorMap = {
    white: '#ffffff',
    yellow: '#ffff00',
    orange: '#ffa500',
    red: '#ff0000',
    green: '#00ff00',
    blue: '#0000ff'
  };

  // Define which colors go on which face
  const faceColors = {
    U: 'white',   // up
    D: 'yellow',  // down
    L: 'orange',  // left
    R: 'red',     // right
    F: 'green',   // front
    B: 'blue'     // back
  };

  // Generate all 27 positions (x, y, z from -1, 0, 1)
  const positions = [];
  for (let x = -1; x <= 1; x++) {
    for (let y = -1; y <= 1; y++) {
      for (let z = -1; z <= 1; z++) {
        positions.push({ x, y, z });
      }
    }
  }

  // Determine which faces need colors for each small cube
  const getColorsForPosition = (x, y, z) => {
    return {
      right: x === 1 ? faceColors.R : null,
      left: x === -1 ? faceColors.L : null,
      up: y === 1 ? faceColors.U : null,
      down: y === -1 ? faceColors.D : null,
      front: z === 1 ? faceColors.F : null,
      back: z === -1 ? faceColors.B : null,
    };
  };

  return (
    <group>
      {positions.map((pos, idx) => {
        const colors = getColorsForPosition(pos.x, pos.y, pos.z);
        // Skip center cube (all faces null)
        const hasAnyColor = Object.values(colors).some(c => c !== null);
        if (!hasAnyColor) return null;
        
        return (
          <SmallCube
            key={idx}
            position={[pos.x, pos.y, pos.z]}
            colors={{
              right: colors.right ? colorMap[colors.right] : null,
              left: colors.left ? colorMap[colors.left] : null,
              up: colors.up ? colorMap[colors.up] : null,
              down: colors.down ? colorMap[colors.down] : null,
              front: colors.front ? colorMap[colors.front] : null,
              back: colors.back ? colorMap[colors.back] : null,
            }}
          />
        );
      })}
    </group>
  );
};

// Main Cube3D Page Component
const Cube3D = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { solution, cubeState } = location.state || { solution: 'No solution', cubeState: null };

  return (
    <div className="cube-3d">
      <button className="back-btn montserrat-alternates-regular" onClick={() => navigate('/input')}>
        ← Back
      </button>
      <h2 className="montserrat-alternates-semibold">3D Cube View</h2>
      <div className="canvas-container">
        <Canvas style={{ background: '#f0f0f0', borderRadius: '12px' }}>
          <PerspectiveCamera makeDefault position={[4, 3, 5]} />
          <OrbitControls enableZoom={true} enablePan={true} />
          <ambientLight intensity={0.6} />
          <directionalLight position={[5, 5, 5]} intensity={1} />
          <directionalLight position={[-5, -5, -5]} intensity={0.3} />
          <RubiksCube />
        </Canvas>
      </div>
      <div className="solution-text montserrat-alternates-regular">
        <strong>Solution:</strong> {solution}
      </div>
    </div>
  );
};

export default Cube3D;
